# WRONG: including a, b, c in the search; trivial solutions like
# 'man' or 'king' will often outscore 'queen'
def solve_bad(a, b, c, wv):
    target = wv[b] - wv[a] + wv[c]
    # Does NOT exclude a, b, c from candidates
    results = wv.similar_by_vector(target, topn=5)
    return results  # 'man', 'king', or 'woman' likely appear at top

# RIGHT: exclude the query words
def solve_good(a, b, c, wv):
    return wv.most_similar(
        positive=[b, c], negative=[a], topn=5
    )   # gensim excludes a, b, c automatically
